func (f *Formatter) Format(data interface{}) error {
	switch f.outputFormat {
	case "json":
		return f.FormatJSON(data)
	case "yaml":
		return f.FormatYAML(data)
	case "stdout":
		return NewTableFormatter().Format(data)
	case "csv":
		return f.FormatCSV(data)
	case "multi-csv":
		return f.FormatMultiCSV(data)
	case "xlsx", "excel":
		return f.FormatXLSX(data)
	default:
		return fmt.Errorf("unsupported format: %s", f.outputFormat)
	}
}

// NewFormatter creates a new formatter instance
func NewFormatter(format, file string) *Formatter {
	return &Formatter{
		outputFormat: format,
		outputFile:   file,
	}
}

func (f *Formatter) FormatJSON(data interface{}) error {
	jsonFormatter := NewJSONFormatter(f.outputFile)
	return jsonFormatter.Format(data)
}

func (f *Formatter) FormatYAML(data interface{}) error {
	yamlFormatter := NewYAMLFormatter(f.outputFile)
	return yamlFormatter.Format(data)
}

func (f *Formatter) FormatTable(data interface{}) error {
	return NewTableFormatter().Format(data)
}

// FormatCSV formats data as CSV and routes to appropriate CSV formatter
func (f *Formatter) FormatCSV(data interface{}) error {
	return NewCSVFormatter(f.outputFile).Format(data)
}

// FormatXLSX formats data as Excel workbook with multiple sheets
func (f *Formatter) FormatXLSX(data interface{}) error {
	return NewXLSXFormatter(f.outputFile).Format(data)
}

// FormatMultiCSV formats data as multiple CSV files (one per category)
func (f *Formatter) FormatMultiCSV(data interface{}) error {
	return NewMultiCSVFormatter(f.outputFile).Format(data)
}

